const watermark = $('Get Watermark').first().json;
const lastRunAt = watermark?.last_run_at
  ? new Date(watermark.last_run_at)
  : new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);
const since = lastRunAt.toISOString().split('T')[0];
return [{ json: { since, lastRunAt: lastRunAt.toISOString(), limit: 500 } }];

// apiprod.dol.gov/v4 returns { data: [...] }
// Field-level API filters are not supported — filter client-side
const raw = $input.first().json;
const allRows = Array.isArray(raw?.data) ? raw.data : (Array.isArray(raw) ? raw : []);

const since = new Date($('Set Fetch Params').first().json.lastRunAt);

const inspections = allRows.filter(r => {
  const naics = String(r.naics_code ?? '');
  const isConstruction = naics.startsWith('23') || r.safety_const === 'X';
  const openDate = r.open_date ? new Date(r.open_date) : null;
  const isNew = openDate && openDate > since;
  return isConstruction && isNew;
});

if (!inspections.length) {
  return [{ json: { _no_results: true, total_fetched: allRows.length } }];
}

// Return ONE item with the full inspection list so the next node runs once
return [{ json: { inspections, activity_nrs: inspections.map(r => r.activity_nr) } }];

// Inspections from Filter Inspections node (one item with array)
const inspections = $('Filter Inspections').first().json.inspections || [];
const targetIds = new Set(inspections.map(r => String(r.activity_nr)));

// Violations from current input
const violRaw = $input.first().json;
const allViols = Array.isArray(violRaw?.data) ? violRaw.data : [];

// Group violations by activity_nr — only for our inspections
// viol_type: S=serious, W=willful, R=repeat, O=other
const violMap = {};
for (const v of allViols) {
  const key = String(v.activity_nr);
  if (!targetIds.has(key)) continue;
  if (!violMap[key]) violMap[key] = { serious:0, willful:0, repeat:0, other:0, initial:0, current:0 };
  const t = String(v.viol_type ?? '').toUpperCase();
  if (t === 'S') violMap[key].serious++;
  else if (t === 'W') violMap[key].willful++;
  else if (t === 'R') violMap[key].repeat++;
  else violMap[key].other++;
  violMap[key].initial  += parseFloat(v.initial_penalty  ?? 0) || 0;
  violMap[key].current  += parseFloat(v.current_penalty  ?? 0) || 0;
}

// Merge and return one item per inspection
return inspections.map(r => {
  const key = String(r.activity_nr);
  const v = violMap[key] || {};
  return {
    json: {
      inspection_id:      String(r.activity_nr ?? '').trim(),
      establishment_name: String(r.estab_name  ?? '').trim(),
      inspection_date:    r.open_date ? r.open_date.split('T')[0] : null,
      naics:              String(r.naics_code ?? '').trim() || null,
      naics_description:  null,
      city:               r.site_city  ?? null,
      state:              r.site_state ?? null,
      zip:                r.site_zip   ?? null,
      penalty_initial:    v.initial || null,
      penalty_current:    v.current || null,
      citations_serious:  v.serious || 0,
      citations_willful:  v.willful || 0,
      citations_repeat:   v.repeat  || 0,
      citations_other:    v.other   || 0,
      raw_payload:        JSON.stringify(r)
    }
  };
});

const items = $input.all();
const rowsSynced = items.length;
const promoted = items.filter(i => {
  try { return JSON.parse(i.json?.result ?? '{}')?.ok === true; } catch { return false; }
}).length;
return [{ json: { rows_synced: rowsSynced, promoted } }];

